import django
django.setup()
from django.urls import get_resolver

resolver = get_resolver()
patterns = []

def extract_patterns(urlpatterns, prefix=''''):
    for pattern in urlpatterns:
        if hasattr(pattern, ''url_patterns''):
            extract_patterns(pattern.url_patterns, prefix + str(pattern.pattern))
        else:
            if ''account'' in str(pattern.pattern) or ''account'' in str(getattr(pattern, ''name'', '''')):
                if ''email'' in str(pattern.pattern) or ''email'' in str(getattr(pattern, ''name'', '''')):
                    patterns.append({
                        ''pattern'': prefix + str(pattern.pattern),
                        ''name'': getattr(pattern, ''name'', ''no-name'')
                    })

extract_patterns(resolver.url_patterns)

for p in sorted(patterns, key=lambda x: x[''pattern'']):
    print(f""{p[''pattern'']:60} {p[''name'']}"")
